export const meta = {
  name: 'cross-model-challenge-autonomy-audit',
  description: 'Ladder the autonomy-grant pause-drift audit through Opus 4.8 then Fable 5 for adversarial cross-model challenge, each stage handing the next a compressed brief instead of raw source',
  phases: [
    { title: 'Opus 4.8 Challenge', detail: 'spot-check load-bearing claims against live repo state, write compressed brief' },
    { title: 'Fable 5 Verdict', detail: 'final judgment on Opus brief, not raw audit' },
  ],
}

const WS = '/Users/brien/Workspaces'

phase('Opus 4.8 Challenge')

const sonnetBrief = `You are auditing a root-cause diagnosis and a live fix written by a Sonnet 5 agent earlier today (2026-07-03) in Brien's Workspaces repo. Your job is NOT to re-derive the whole investigation. It is to adversarially spot-check the load-bearing claims below against the real repo state, then hand a compressed brief to a THIRD model for final judgment. Budget your reads: verify the claims listed, do not re-read the entire audit trail from scratch.

CONTEXT: Brien complained the AI keeps forgetting standing autonomy grants and pausing for unnecessary permission on work he already authorized. Sonnet ran a 15-agent research workflow, found the enforcement hook fabric is architecturally reactive-only (Claude Code hooks fire on discrete events, never mid-generation, so hedging can only be caught after it's written), found the lexical regex Stop-hook layer was frozen 5 weeks ago as unconvergeable, and found the one structural non-lexical detector (Layer 4.2) has been stuck warn-only for 35+ days.

CLAIM SET TO VERIFY (read the cited files directly, do not trust this summary):

